275	// ── Single-case runner ───────────────────────────────────────
276	
277	fn rbtdb_run_single(args: &[String]) -> ExitCode {
278	    let fixture = match args.first() {
279	        Some(f) => f,
280	        None => {
281	            rbtd::rbtdrg_error_now!(
282	                "rbtd single: usage: rbtd single <fixture> [case]\n\
283	                 omit case to list all cases for the fixture"
284	            );
285	            rbtdb_list_fixtures();
286	            return ExitCode::FAILURE;
287	        }
288	    };
289	
290	    if !RBTDRC_FIXTURES.iter().any(|f| f.name == *fixture) {
291	        rbtd::rbtdrg_error_now!("rbtd single: unknown fixture '{}'", fixture);
292	        rbtdb_list_fixtures();
293	        return ExitCode::FAILURE;
294	    }
295	
296	    // Set up execution context early — needed for charge check and case execution
297	    let project_root = match std::env::current_dir() {
298	        Ok(p) => p,
299	        Err(e) => rbtd::rbtdrg_fatal_now!("rbtd: cannot determine working directory: {}", e),
300	    };
301	
302	    let roots = match rbtdb_allocate_roots() {
303	        Ok(r) => r,
304	        Err(msg) => rbtd::rbtdrg_fatal_now!("{}", msg),
305	    };
306	
307	    // Context is required for every case execution path (rbtdrc_with_ctx).
308	    // Fixtures with a setup hook (crucible charge) additionally verify their
309	    // crucible is charged externally — single-case mode never charges.
310	    let mut ctx = rbtdri_Context::new(
311	        &project_root,
312	        fixture,
313	        &roots.burv_temp_root,
314	        &roots.burv_output_root,
315	    );
316	
317	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
318	        Some(f) => f,
319	        None => rbtd::rbtdrg_fatal_now!(
320	            "rbtd single: fixture '{}' has no registered Fixture",
321	            fixture
322	        ),
323	    };
324	
325	    if fixture_def.setup.is_some() {
326	        match rbtdri_invoke_global(
327	            &mut ctx,
328	            RBTDGC_CRUCIBLE_ACTIVE,
329	            &[fixture],
330	            &[],
331	        ) {
332	            Ok(r) if r.exit_code == 0 => {}
333	            _ => rbtd::rbtdrg_fatal_now!(
334	                "rbtd single: crucible not charged for '{}'\n\
335	                 charge first: tt/rbw-cC.Charge.{}.sh",
336	                fixture, fixture
337	            ),
338	        }
339	    }
340	
341	    rbtdrc_set_context(ctx);
342	
343	    let cases = fixture_def.cases;
344	
345	    // No case argument — list all cases
346	    let case_name = match args.get(1) {
347	        None => {
348	            rbtdre_list_cases(cases);
349	            return ExitCode::SUCCESS;
350	        }
351	        Some(n) => n,
352	    };
353	
354	    // Find the case
355	    let case = match rbtdre_find_case(cases, case_name) {
356	        Some(c) => c,
357	        None => {
358	            rbtd::rbtdrg_error_now!(
359	                "rbtd single: case '{}' not found in fixture '{}'",
360	                case_name, fixture
361	            );
362	            rbtdre_list_cases(cases);
363	            return ExitCode::FAILURE;
364	        }
365	    };
366	
367	    let colors = rbtdre_detect_colors();
368	    let result = match rbtdre_run_single_case(case, &colors, &roots.trace_root) {
369	        Ok(r) => r,
370	        Err(msg) => rbtd::rbtdrg_fatal_now!("rbtd: case execution error: {}", msg),
371	    };
372	
373	    rbtdre_print_summary(&result, &colors);
374	
375	    if result.failed > 0 {
376	        ExitCode::FAILURE
377	    } else {
378	        ExitCode::SUCCESS
379	    }
380	}
